export function nextGeneration(liveCells: Cell[]): Cell[] {
  const isLive = (x: number, y: number): boolean =>
    liveCells.some(([cx, cy]) => cx === x && cy === y);
  const neighborsOf = ([x, y]: Cell): Cell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(([x, y]) => isLive(x, y)).length;
  const survivors = liveCells.filter((cell) => survives(countLiveNeighbors(cell)));
  const deadNeighborCandidates = liveCells
    .flatMap(neighborsOf)
    .filter(([x, y]) => !isLive(x, y));
  const births = deadNeighborCandidates.filter(
    (cell, i) =>
      deadNeighborCandidates.findIndex(([cx, cy]) => cx === cell[0] && cy === cell[1]) === i
      && countLiveNeighbors(cell) === 3,
  );
  return [...survivors, ...births];
}

